.shape-tile {
  width: 72px;
  height: 72px;
  border-radius: 18px;
  touch-action: none;
}

/* Increase touch target size for mobile */
.shape-tile::after {
  content: '';
  position: absolute;
  top: -24px;
  left: -24px;
  right: -24px;
  bottom: -24px;
}

